mapper.select:
SELECT id, project_id, name, role, model_tier, status, parent_id, prompt
FROM project_agents
WHERE project_id = #{project_id} AND id = #{id}

SELECT id, project_id, name, role, model_tier, status, parent_id, prompt
FROM project_agents
WHERE project_id = #{project_id}
ORDER BY id ASC
LIMIT #{size} OFFSET #{from}

mapper.delete:
DELETE FROM project_agents
WHERE project_id = #{project_id}
  AND id = #{id}

mapper.update:
UPDATE project_agents
SET status = #{status, jdbcType=VARCHAR},
    updated_at = CURRENT_TIMESTAMP
WHERE project_id = #{project_id}
  AND id = #{agent, typeHandler=reengineering.ddd.mybatis.support.RefIntegerTypeHandler}
